<template><div class="page"><h2>直播面板</h2><div class="grid grid-2"><div class="card"><el-alert title="OBS：未连接，本页先完成实时 TTS 发送区" type="info" show-icon :closable="false"/><el-form label-position="top" style="margin-top:14px"><el-form-item label="选择脚本"><el-select class="full" v-model="selectedScript" @change="useScript"><el-option v-for="s in scripts" :key="s.id" :label="s.title" :value="s.id"/></el-select></el-form-item><el-form-item label="选择声音"><el-select class="full" v-model="form.voiceModelId"><el-option v-for="v in voices" :key="v.id" :label="v.name" :value="v.id"/></el-select></el-form-item><el-form-item label="发送文本（Ctrl + Enter）"><el-input v-model="form.text" type="textarea" :rows="9" @keydown.ctrl.enter="send"/></el-form-item><el-button type="primary" :loading="loading" @click="send">发送 TTS</el-button></el-form></div><div class="card"><h3>发送历史</h3><audio v-if="audioUrl" :src="audioUrl" controls class="full"/><div v-for="h in history" :key="h.time" class="history-item"><div>{{h.text}}</div><small class="muted">{{h.time}}</small></div></div></div></div></template>
<script setup>import { reactive,ref,onMounted } from 'vue';import { ElMessage } from 'element-plus';import { getVoiceList } from '../api/voice';import { getScriptList } from '../api/scripts';import { convertTTS } from '../api/tts';const voices=ref([]),scripts=ref([]),selectedScript=ref(null),history=ref([]),audioUrl=ref(''),loading=ref(false);const form=reactive({voiceModelId:null,text:'',speed:1,pitch:1});function useScript(id){const s=scripts.value.find(x=>x.id===id);if(s)form.text=s.content||''}async function send(){if(!form.voiceModelId||!form.text)return ElMessage.warning('请选择声音并输入文本');loading.value=true;try{const d=await convertTTS(form);audioUrl.value=d.audioUrl||`/api/tts/download/${d.taskId}`;history.value.unshift({text:form.text,time:new Date().toLocaleString()});ElMessage.success('已发送')}finally{loading.value=false}}onMounted(async()=>{voices.value=await getVoiceList().catch(()=>[])||[];scripts.value=await getScriptList().catch(()=>[])||[]})</script>
